-- ============================================================
-- Módulo "Instagram N3" — Metrifica Labs
-- ------------------------------------------------------------
-- Cria o módulo de diretrizes do sistema Posts N3 + flow.
-- Content em base64 para evitar bug de encoding UTF-8 no Windows.
-- ============================================================

-- 1. Módulo de diretrizes
INSERT INTO modules (slug, name, module_ref, content)
VALUES (
  'instagram-n3-guidelines',
  'Instagram N3 — Diretrizes',
  'IG-N3',
  convert_from(decode('', 'base64'), 'UTF8')
)
ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, content = EXCLUDED.content;

-- 2. Flow que referencia o módulo de diretrizes
INSERT INTO flows (slug, name, description, module_slugs)
VALUES (
  'instagram-n3',
  'Instagram N3',
  convert_from(decode('R2VyYSBvIGNvbnRlw7pkbyBkZSBDYXJkcyBwYXJhIFBvc3RzIE4zIGRvIEluc3RhZ3JhbSDigJQgY2Fycm9zc8OpaXMgYmFzZWFkb3Mgbm8gTcOpdG9kbyBOMzogUG9zdCAxLzkgKE8gTcOpdG9kbyksIDIvOSAoQSBWaWRhIEFww7NzKSwgMy85IChPIENvbnRyYXBvbnRvKSBlIDEwLzkgKEFwbGljYcOnw6NvIFJlYWwpLg==', 'base64'), 'UTF8'),
  ARRAY['instagram-n3-guidelines']
)
ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, module_slugs = EXCLUDED.module_slugs;

-- 3. Ativa a feature para a org metrifica
UPDATE organizations
SET config = jsonb_set(
  COALESCE(config, '{}'::jsonb),
  '{enabled_features}',
  (
    SELECT to_jsonb(array(
      SELECT DISTINCT e
      FROM unnest(
        COALESCE(
          ARRAY(SELECT jsonb_array_elements_text(config->'enabled_features')),
          ARRAY[]::text[]
        ) || ARRAY['instagram_n3']
      ) AS e
    ))
  )
)
WHERE slug = 'metrifica';
